@font-face {
  font-family: 'Custom Web Font';
  src: url('/fonts/CustomWebFont.woff2') format('woff2'),
       url('/fonts/CustomWebFont.woff') format('woff');
  font-weight: 400;
  font-style: normal;
  font-display: swap; /* 'swap' provides a fallback font immediately, then swaps */
}

body {
  font-family: 'Custom Web Font', 'Helvetica Neue', Arial, sans-serif;
}
